mapper.select:
select fd.*,temp.* from (select
from fnd_dept fd where 1 = 1 and fd.enabled_flag = 1 and fd.id = #{deptId,jdbcType=BIGINT}
) as fd left join ( select
,
,
from ac_dept_attendance ada,ac_regime ar,ac_calendar_header ach where ada.enabled_flag = 1 and ada.regime_id = ar.id and ada.calendar_header_id = ach.id
AND CONVERT(VARCHAR(10),GETDATE(),110) >= ADA.take_effect_date AND CONVERT(VARCHAR(10),GETDATE(),110) <= ISNULL( ADA.invalid_date, dateadd( d, 1, CONVERT(VARCHAR(10),GETDATE(),110) ) )
) AS temp ON fd.fd_id = temp.ada_dept_id ORDER BY fd.fd_id

select fd.*,temp.* from (select
from fnd_dept fd where 1 = 1 and fd.enabled_flag = 1 and fd.deleted_flag = 0
and fd.id = #{criteria.deptId,jdbcType=BIGINT}
and fd.dept_name like #{criteria.deptName, jdbcType=VARCHAR}
) as fd left join ( select
,
,
