AND CONVERT(VARCHAR(10),GETDATE(),110) >= ADA.take_effect_date AND CONVERT(VARCHAR(10),GETDATE(),110) <= ISNULL( ADA.invalid_date, dateadd( d, 1, CONVERT(VARCHAR(10),GETDATE(),110) ) )
and ar.id = #{criteria.regimeId,jdbcType=BIGINT}
and (CONVERT(VARCHAR(10),GETDATE(),110) BETWEEN ada.take_effect_date and ISNULL( ada.invalid_date, dateadd( d, 1, CONVERT(VARCHAR(10),GETDATE(),110) ) )
or ada.take_effect_date > CONVERT(VARCHAR(10),GETDATE(),110) )
AND CONVERT(VARCHAR(10),GETDATE(),110) >= ADA.take_effect_date AND CONVERT(VARCHAR(10),GETDATE(),110) <= ISNULL( ADA.invalid_date, dateadd( d, 1, CONVERT(VARCHAR(10),GETDATE(),110) ) )
) AS temp ON fd.fd_id = temp.ada_dept_id ORDER BY fd.fd_id

